"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";

interface ShippingAddress {
  line1: string;
  city: string;
  state: string;
  zip: string;
}

interface LocationData {
  address?: string;
  city?: string;
  state?: string;
  zip?: string;
  screenId?: string;
  locationId?: string;
}

export function StepDeviceOrder() {
  const router = useRouter();
  const [locationData, setLocationData] = useState<LocationData>({});
  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [shippingAddress, setShippingAddress] = useState<ShippingAddress>({
    line1: "",
    city: "",
    state: "",
    zip: "",
  });

  useEffect(() => {
    fetch("/api/onboarding/location-data")
      .then((r) => r.json())
      .then((data: LocationData) => {
        setLocationData(data);
        setShippingAddress({
          line1: data.address ?? "",
          city: data.city ?? "",
          state: data.state ?? "",
          zip: data.zip ?? "",
        });
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  function updateField(field: keyof ShippingAddress, value: string) {
    setShippingAddress((prev) => ({ ...prev, [field]: value }));
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      const res = await fetch("/api/onboarding/order", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          shippingAddress,
          screenId: locationData.screenId,
          locationId: locationData.locationId,
        }),
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error ?? "Failed to place order");
      }

      toast.success("Order placed! Your device is on the way.");
      router.push("/dashboard");
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Something went wrong");
    } finally {
      setIsSubmitting(false);
    }
  }

  if (loading) {
    return <div className="py-8 text-center text-muted-foreground text-sm">Loading...</div>;
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-5">
      <div>
        <h2 className="text-lg font-semibold">Order Your Device</h2>
        <p className="text-sm text-muted-foreground mt-1">Confirm your shipping address to place your order.</p>
      </div>

      <div className="space-y-4">
        <h3 className="text-sm font-medium">Shipping Address</h3>
        <div className="space-y-2">
          <Label htmlFor="line1">Street Address</Label>
          <Input
            id="line1"
            value={shippingAddress.line1}
            onChange={(e) => updateField("line1", e.target.value)}
            placeholder="123 Main St"
            required
          />
        </div>
        <div className="grid grid-cols-3 gap-3">
          <div className="col-span-1 space-y-2">
            <Label htmlFor="city">City</Label>
            <Input
              id="city"
              value={shippingAddress.city}
              onChange={(e) => updateField("city", e.target.value)}
              placeholder="Phoenix"
              required
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="state">State</Label>
            <Input
              id="state"
              value={shippingAddress.state}
              onChange={(e) => updateField("state", e.target.value)}
              placeholder="AZ"
              required
            />
          </div>
          <div className="space-y-2">
            <Label htmlFor="zip">ZIP</Label>
            <Input
              id="zip"
              value={shippingAddress.zip}
              onChange={(e) => updateField("zip", e.target.value)}
              placeholder="85001"
              required
            />
          </div>
        </div>
      </div>

      <Button type="submit" className="w-full" disabled={isSubmitting}>
        {isSubmitting ? "Placing Order..." : "Place Order"}
      </Button>
    </form>
  );
}
